  `question_bank_id` bigint(20) unsigned NOT NULL,
  `subject_id` bigint(20) unsigned NOT NULL,
  `created_by` bigint(20) unsigned NOT NULL,
  `type` varchar(30) NOT NULL,
  `question_text` longtext NOT NULL,
  `question_text_en` longtext DEFAULT NULL,
  `explanation` longtext DEFAULT NULL,
  `explanation_en` longtext DEFAULT NULL,
  `points` decimal(8,2) NOT NULL DEFAULT 1.00,
  `difficulty` varchar(20) NOT NULL DEFAULT 'medium',
  `import_source` varchar(30) DEFAULT NULL,
  `short_answer_key` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `questions_question_bank_id_foreign` (`question_bank_id`),
  KEY `questions_subject_id_foreign` (`subject_id`),
  KEY `questions_created_by_foreign` (`created_by`),
  CONSTRAINT `questions_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `questions_question_bank_id_foreign` FOREIGN KEY (`question_bank_id`) REFERENCES `question_banks` (`id`) ON DELETE CASCADE,
  CONSTRAINT `questions_subject_id_foreign` FOREIGN KEY (`subject_id`) REFERENCES `subjects` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=265 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

